<template>
  <div id="detail">
    <el-container>
       <template>
          <el-alert title="addTodo is successful!" type="success" show-icon center v-show="isEdit"></el-alert>
        </template>
      <el-header style="line-height:60px;">
        <el-row type="flex" justify="center">
          <el-col :lg="16" :xs="24">
            <el-page-header @back="$router.go(-1)" content="detail" title="return"></el-page-header>
          </el-col>
        </el-row>
      </el-header>
      <el-main>
        <el-row type="flex" justify="center">
          <el-col :xs="24" :sm="16">
            <el-input clearable v-model="todo.title" placeholder="input todo of title"></el-input>
            <el-input
              type="textarea"
              :rows="4"
              placeholder="input your todo content"
              v-model="todo.content"
              clearable
            ></el-input>
          </el-col>
        </el-row>
        <el-row style="padding:10px;">
          <el-col>
            <el-radio v-model="todo.completed" :label="true">completed</el-radio>
            <el-radio v-model="todo.completed" :label="false">doing...</el-radio>
          </el-col>
           <p>written time : {{ todo.updateTime = new Date().toLocaleString() }}</p>
        </el-row>
        <el-row>
          <el-col>
            <el-button type="primary" @click="editTodo">Edit</el-button>
          </el-col>
        </el-row>
      </el-main>
    </el-container>
  </div>
</template>
<script>
export default {
  data() {
    return {
      id: this.$route.params.id,
      todo: {},
      radio: 'false' ,
      isEdit: false
    };
  },
  methods: {
    editTodo() {
      this.$http.put("https://wd0495013240cregbc.wilddogio.com/todos/" + this.id + ".json", this.todo).then((res) => {
        // console.log(res.data);
        this.todo = res.data;
        
        this.isEdit = true;
        setTimeout(() => {
          this.isEdit = false;
          this.$router.push("/todo");
        }, 3000);
      });
    }
  },
  created() {
    this.$http.get("https://wd0495013240cregbc.wilddogio.com/todos/" + this.id + ".json").then(res => {
      // console.log(res.data);
      this.todo = res.data;
    });
  }
};
</script>



